 1	import type { FC } from 'react';
 2	import { TableCell } from 'src/modules/Providers/utils/components/TableCell/TableCell';
 3	import { TableEmptyCell } from 'src/modules/Providers/utils/components/TableCell/TableEmptyCell';
 4	import type { VmData } from 'src/modules/Providers/views/details/tabs/VirtualMachines/components/VMCellProps';
 5	import { PROVIDER_TYPES } from 'src/providers/utils/constants';
 6	
 7	import type { Concern } from '@kubev2v/types';
 8	import { Split, SplitItem } from '@patternfly/react-core';
 9	import { isEmpty } from '@utils/helpers';
10	
11	import ConcernPopover from './components/ConcernsPopover';
12	import { groupConcernsByCategory } from './utils/category';
13	import { orderedConcernCategories } from './utils/constants';
14	
15	const VirtualMachineConcernsCell: FC<{ vmData: VmData }> = ({ vmData }) => {
16	  const concerns: Concern[] =
17	    vmData?.vm?.providerType === PROVIDER_TYPES.openshift ? [] : vmData?.vm?.concerns;
18	  if (!concerns || isEmpty(concerns)) {
19	    return <TableEmptyCell />;
20	  }
21	
22	  const groupedConcerns = groupConcernsByCategory(concerns);
23	
24	  return (
25	    <TableCell>
26	      <Split hasGutter>
27	        {orderedConcernCategories.map((category) => {
28	          const hasConcernCategory = concerns?.find((concern) => concern.category === category);
29	
30	          if (hasConcernCategory) {
31	            return (
32	              <SplitItem key={category}>
33	                <ConcernPopover category={category} concerns={groupedConcerns[category] || []} />
34	              </SplitItem>
35	            );
36	          }
37	
38	          return null;
39	        })}
40	      </Split>
41	    </TableCell>
42	  );
43	};
44	
45	export default VirtualMachineConcernsCell;

